#include <stdio.h>
int main() {
    int T, n, a[100005], i, j, min, max, ans;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &n);
        for (i = 0; i < n; i++) scanf("%d", &a[i]);
        min = a[0]; max = a[0];
        for (i = 1; i < n; i++) {
            if (a[i] < min) min = a[i];
            if (a[i] > max) max = a[i];
        }
        ans = 0;
        while (min < max) {
            min *= 2;
            ans++;
        }
        printf("%d\n", ans);
    }
    return 0;
}

