import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[] a = new int[n];
            for (int i = 0; i < n; i++) a[i] = sc.nextInt();
            int min = a[0];
            int max = a[0];
            for (int i = 1; i < n; i++) {
                if (a[i] < min) min = a[i];
                if (a[i] > max) max = a[i];
            }
            int ans = 0;
            while (min < max) {
                min *= 2;
                ans++;
            }
            System.out.println(ans);
        }
    }
}

