const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let T;
let input = [];
readline.on('line', line => {
    if (i === 0) {
        T = parseInt(line);
    } else {
        input.push(line);
    }
    i++;
    if (i === T * 2 + 1) {
        for (let j = 0; j < T; j++) {
            let n = parseInt(input[j * 2]);
            let a = input[j * 2 + 1].split(' ').map(x => parseInt(x));
            let min = Math.min(...a);
            let max = Math.max(...a);
            let ans = 0;
            while (min < max) {
                min *= 2;
                ans++;
            }
            console.log(ans);
        }
    }
});
